const data = $input.first().json.body.data;

return [{
  json: {
    email: data.customer.email,
    firstName: data.customer.firstName || '',
    productName: data.product.name,
    amount: data.order.amount / 100,
    currency: data.order.currency.toUpperCase(),
    sessionId: data.order.sessionId,
    paymentIntentId: data.order.paymentIntentId,
    needsInvoice: data.invoice?.needsInvoice || false,
    invoiceNip: data.invoice?.nip || null,
    invoiceCompany: data.invoice?.companyName || null,
    invoiceAddress: data.invoice?.address || null,
    invoiceCity: data.invoice?.city || null,
    invoicePostalCode: data.invoice?.postalCode || null,
    invoiceCountry: data.invoice?.country || 'PL'
  }
}];

const d = $input.first().json;
const today = new Date().toISOString().split('T')[0];

// Build invoice number from session ID suffix — user may want to adjust this scheme
const suffix = (d.sessionId || 'XXXX').slice(-4).toUpperCase();
const invoiceNumber = `FV/${today.replace(/-/g, '/')}/${suffix}`;

const buyerCity = d.invoicePostalCode
  ? `${d.invoicePostalCode} ${d.invoiceCity}`
  : d.invoiceCity || '-';

// Seller data — EDIT THESE to match your company
const seller = {
  nip: $vars.SELLER_NIP || '0000000000',
  name: $vars.SELLER_NAME || 'Twoja Firma sp. z o.o.',
  address: {
    street: $vars.SELLER_STREET || 'ul. Przykladowa 1',
    city: $vars.SELLER_CITY || '00-001 Warszawa'
  }
};

return [{
  json: {
    invoiceNumber,
    issueDate: today,
    saleDate: today,
    issuePlace: seller.address.city.split(' ').slice(1).join(' ') || 'Warszawa',
    currency: d.currency || 'PLN',
    type: 'VAT',
    seller,
    buyer: {
      nip: d.invoiceNip,
      name: d.invoiceCompany || d.email,
      address: {
        street: d.invoiceAddress || '-',
        city: buyerCity,
        country: d.invoiceCountry || 'PL'
      }
    },
    items: [
      {
        name: d.productName,
        unit: 'szt.',
        quantity: 1,
        unitPrice: d.amount,
        vatRate: 23
      }
    ],
    payment: {
      paid: true,
      date: today,
      method: 'transfer'
    },
    // Pass-through for error logging
    _meta: {
      sessionId: d.sessionId,
      paymentIntentId: d.paymentIntentId,
      buyerEmail: d.email
    }
  }
}];
